// === MODELS.PY ===
const modelsExtracted = $('Extract models.py').all();
const modelsContent = modelsExtracted
  .map(f => `# === ${f.json.fileName || 'models.py'} ===\n${f.json.data || ''}`)
  .join('\n\n');

// === TESTS_MODELS.PY ===
