const testsContent = testsExtracted
  .map(f => `# === ${f.json.fileName || 'tests_models.py'} ===\n${f.json.data || ''}`)
  .join('\n\n');

// === REQUIREMENTS PADRE (dominio completo) ===
const requirementsParent = $('Extract requirements.json').first().json.data;

// === REQUIREMENTS CAPA + CONTEXT ===
const requirementsLayer = $('Extract requirements_models.json').first().json.data;
const context = $('Extract context_models.json').first().json.data;

const pendingIssues  = context?.phases?.phase_4_validation?.pending_issues  || [];
const resolvedIssues = context?.phases?.phase_4_validation?.resolved_issues || [];

// === ARCHITECT RULES ===
const architectureRules = architectExtracted
  .split('\n')
  .filter(line => line.trim().startsWith('- "') || line.trim().startsWith("- '"))
  .map(line => line.trim().replace(/^- ["']|["']$/g, ''))
  .filter(rule => rule.length > 0);

// === DOMAIN CONTEXT — reglas legales del padre ===
const domainContext = {
  project: requirementsParent.project_name,
  stack: requirementsParent.stack,
  domain_rules: (requirementsParent.requirements || []).map(r => ({
    id: r.id,
    module: r.module,
    domain_rules: r.domain_rules || []
  }))
};

// === PAYLOAD FINAL ===
const payload = {
  meta: {
    project_id: requirementsLayer.project_id,
    timestamp: new Date().toISOString(),
    app_context: {
      app_name: "penalcode",
      layer: requirementsLayer.layer,
      architecture_rules: architectureRules
    },
    run_context: {
      previous_pending_issues: pendingIssues,
      previously_resolved:     resolvedIssues,
