return { contextData: JSON.stringify(contextUpdate) };

const verdict = $('Update Context JS').first().json;
const issues = verdict.issues || [];

if (issues.length === 0) {
  return {
    report: '# CRITIC REPORT — ' + new Date().toISOString() + '\n**Status:** ' + verdict.status + '\n**Summary:** ' + verdict.summary + '\n\nNo hay issues que resolver.',
    hasIssues: false
  };
}

const byConfidence = { high: [], medium: [], low: [] };
for (const issue of issues) {
  const key = issue.confidence || 'low';
  if (byConfidence[key]) byConfidence[key].push(issue);
}

const formatIssue = (issue, idx) => {
  return '### Issue ' + (idx + 1) + ' — ' + issue.requirement_id + ' · ' + issue.type + '\n' +
    '- **Archivo:** ' + issue.location + '\n' +
    '- **Descripcion:** ' + issue.description + '\n' +
    '- **Evidencia:** ' + issue.evidence + '\n' +
    '- **Fix sugerido:** ' + issue.suggested_fix;
};

const sections = [];
if (byConfidence.high.length > 0) {
  const items = byConfidence.high.map((i, idx) => formatIssue(i, idx)).join('\n\n---\n\n');
  sections.push('## HIGH confidence\n\n' + items);
}
if (byConfidence.medium.length > 0) {
  const items = byConfidence.medium.map((i, idx) => formatIssue(i, idx)).join('\n\n---\n\n');
  sections.push('## MEDIUM confidence\n\n' + items);
}
if (byConfidence.low.length > 0) {
  const items = byConfidence.low.map((i, idx) => formatIssue(i, idx)).join('\n\n---\n\n');
  sections.push('## LOW confidence\n\n' + items);
}

const header = '# CRITIC REPORT — ' + new Date().toISOString() + '\n**Status:** ' + verdict.status + '\n**Summary:** ' + verdict.summary;

const instructions = '\n\n---\n## Instrucciones para Cline\n' +
'**REGLAS ESTRICTAS — leer antes de tocar cualquier archivo:**\n\n' +
'1. Aplica UNICAMENTE los fixes listados en este reporte\n' +
'2. NO refactorices codigo que no este mencionado en un issue\n' +
'3. NO cambies nombres de campos, metodos o clases existentes\n' +
'4. NO elimines tests existentes — solo agrega assertions faltantes\n' +
'5. NO cambies definiciones de campos en models.py — solo agrega metodos clean() o save()\n' +
'6. Si un fix requiere tocar codigo que no esta en el issue → detente y reporta\n' +
'7. Orden de ejecucion: HIGH → MEDIUM → LOW\n' +
'8. Al terminar: corre python manage.py test apps.penalcode y reporta resultado\n';

const report = header + '\n\n---\n\n' + sections.join('\n\n') + instructions;

