const deepseekRaw = $('DeepSeek Critic').first().json.output || '';
const kimiRaw     = $('Kimi Critic').first().json.output     || '';

// ── Leer requirements para filtro mecánico ────────────────────────────────────
let requirements = [];
try {
  const reqRaw = $('Read requirements_models').first().json;
  requirements = reqRaw.requirements || [];
} catch(e) {
  requirements = [];
}

// ── Extraer todos los OOS patterns del requirements ───────────────────────────
const oosPatterns = [];
requirements.forEach(req => {
  (req.out_of_scope || []).forEach(oos => {
    if (oos.pattern) oosPatterns.push(oos.pattern.toLowerCase());
  });
});

// ── Strip markdown + parse ────────────────────────────────────────────────────
const stripAndParse = (raw, fallback) => {
  try {
    const clean = raw
      .replace(/```json\s*/gi, '')
      .replace(/```\s*/g, '')
      .trim();
    return JSON.parse(clean);
  } catch (e1) {
    try {
      const lastBrace = raw.lastIndexOf('}');
      if (lastBrace === -1) throw new Error('no closing brace');
      const partial = raw.substring(0, lastBrace + 1);
      const clean = partial
        .replace(/```json\s*/gi, '')
        .replace(/```\s*/g, '')
        .trim();
      return JSON.parse(clean);
    } catch (e2) {
      return fallback;
    }
  }
};

const deepseek = stripAndParse(deepseekRaw, {
  status: 'error',
  issues: [],
  summary: 'Parse error DeepSeek'
});

const kimiResult = stripAndParse(kimiRaw, {
  verdict: 'parse_error',
  confirmed_issues: [],
  refuted_issues: [],
  summary: 'Kimi truncado'
});

// ── RFC 2119 MAY filter ───────────────────────────────────────────────────────
const MAY_PATTERNS = [
  'objeto_id', 'objeto_tipo', 'detalles', 'ip_address',
  'super().clean', 'raise ValidationError',
  'race conditions', 'unique=True',
  'ForeignKey null=False', 'null=False',
  'rol abogado firmante', 'multiples alertas',
  'documentos fundacionales', 'domicilio judicial asociados',
  'al menos un defensor', 'clasificacion accion penal',
  'EtapaProcesal catalogo', 'escrito despachado cambio prueba',
  'registro automatico log'
];

const isMayIssue = (issue) => {
  const text = JSON.stringify(issue).toLowerCase();
  return MAY_PATTERNS.some(p => text.includes(p.toLowerCase()));
};

// ── OOS mechanical filter — JS ejecuta, JSON decide ──────────────────────────
const isOosIssue = (issue) => {
  const issueText = (
    (issue.description || '') + ' ' +
    (issue.evidence    || '') + ' ' +
    (issue.type        || '')
  ).toLowerCase();

  return oosPatterns.some(pattern => {
    const tokens = pattern.split(' ').filter(t => t.length > 3);
    return tokens.length > 0 && tokens.every(t => issueText.includes(t));
  });
};

// ── Confirmed issues de Kimi (fuente de verdad) ───────────────────────────────
const confirmedIssues = (kimiResult.confirmed_issues || [])
  .filter(i => i.requirement_id && i.description && !i.refutation)
  .filter(i => !isMayIssue(i))
  .filter(i => !isOosIssue(i));

// ── DeepSeek issues para debug ────────────────────────────────────────────────
const deepseekClean = (deepseek.issues || [])
  .filter(i => i.ac_violated && i.ac_violated.length >= 15)
  .filter(i => !isMayIssue(i))
  .filter(i => !isOosIssue(i));

// ── Status final ──────────────────────────────────────────────────────────────
let finalStatus = 'pass';
if (confirmedIssues.some(i => i.confidence === 'high')) {
  finalStatus = 'fail';
} else if (confirmedIssues.length > 0) {
  finalStatus = 'warn';
}

// ── Consenso ──────────────────────────────────────────────────────────────────
const kimiVerdict   = kimiResult.verdict || 'unknown';
const consensus     = confirmedIssues.length === 0
  ? true
  : (kimiVerdict === 'refuted' || kimiVerdict === 'confirmed');
const requiresHuman = confirmedIssues.length > 0 &&
  (kimiVerdict === 'partial' || kimiVerdict === 'parse_error');

// ── Output ────────────────────────────────────────────────────────────────────
return [{
  json: {
    status:          finalStatus,
    issues:          confirmedIssues,
    refuted:         kimiResult.refuted_issues || [],
    deepseek_issues: deepseekClean,
    summary:         'DeepSeek: ' + (deepseek.summary  || '') +
                     ' | Kimi: '  + (kimiResult.summary || ''),
    consensus,
    requires_human:  requiresHuman,
    votes: {
      deepseek: deepseek.status || 'unknown',
      kimi:     kimiVerdict
    }
  }
}];

