// ── DeepSeek issues para debug ────────────────────────────────────────────────
const deepseekClean = (deepseek.issues || [])
  .filter(i => i.ac_violated && i.ac_violated.length >= 15)
  .filter(i => !isMayIssue(i))
  .filter(i => !isOosIssue(i));

// ── Status final ──────────────────────────────────────────────────────────────
let finalStatus = 'pass';
if (confirmedIssues.some(i => i.confidence === 'high')) {
  finalStatus = 'fail';
} else if (confirmedIssues.length > 0) {
  finalStatus = 'warn';
}

// ── Consenso ──────────────────────────────────────────────────────────────────
const kimiVerdict   = kimiResult.verdict || 'unknown';
const consensus     = confirmedIssues.length === 0
  ? true
  : (kimiVerdict === 'refuted' || kimiVerdict === 'confirmed');
const requiresHuman = confirmedIssues.length > 0 &&
  (kimiVerdict === 'partial' || kimiVerdict === 'parse_error');

// ── Output ────────────────────────────────────────────────────────────────────
return [{
  json: {
    status:          finalStatus,
    issues:          confirmedIssues,
    refuted:         kimiResult.refuted_issues || [],
    deepseek_issues: deepseekClean,
    summary:         'DeepSeek: ' + (deepseek.summary  || '') +
                     ' | Kimi: '  + (kimiResult.summary || ''),
    consensus,
    requires_human:  requiresHuman,
    votes: {
      deepseek: deepseek.status || 'unknown',
      kimi:     kimiVerdict
    }
  }
}];

const payload = JSON.parse($('Assemble Payload JS2').first().json.payload);

const extractSignatures = (code, filename) => {
  const lines = code.split('\n');
  const result = [];
  let insideClass = false;
  let insideMethod = false;
  let methodDepth = 0;
  let classIndent = 0;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const stripped = line.trim();
    const indent = line.length - line.trimStart().length;

    // Líneas vacías — mantener una sola
    if (stripped === '') {
      if (result[result.length - 1] !== '') result.push('');
      continue;
    }

    // Imports — siempre incluir
    if (stripped.startsWith('import ') || stripped.startsWith('from ')) {
      result.push(line);
      continue;
    }

    // Clases — incluir firma completa
    if (stripped.startsWith('class ')) {
      insideClass = true;
      classIndent = indent;
      insideMethod = false;
      result.push(line);
      continue;
    }

    // Meta, choices, constantes de clase — incluir
    if (insideClass && indent > classIndent) {
      const isClassVar = !stripped.startsWith('def ') &&
                         !stripped.startsWith('async def ') &&
                         indent === classIndent + 4;
      if (isClassVar) {
        result.push(line);
        continue;
      }
    }

    // Métodos — incluir solo la firma
         // Métodos críticos — incluir completos
const isCriticalMethod = stripped.includes('def clean(') || 
                         stripped.includes('def save(') ||
                         stripped.includes('def test_') ||
                        stripped.includes('def setUp') ||
                        stripped.includes('def full_clean(');

    if (stripped.startsWith('def ') || stripped.startsWith('async def ')) {
      insideMethod = !isCriticalMethod;
      methodDepth = indent;
      result.push(line);
      if (!isCriticalMethod) {
        result.push(' '.repeat(indent + 4) + '...');
      }
      continue;
    }

// Body de métodos — omitir solo si no es crítico
if (insideMethod && indent > methodDepth) {
  continue;
} else if (!isCriticalMethod) {
  insideMethod = false;
}
    // Body de métodos — omitir
    if (insideMethod && indent > methodDepth) {
      continue;
    } else {
      insideMethod = false;
    }

    // Todo lo demás dentro de clase — incluir
    if (insideClass && indent > classIndent) {
      result.push(line);
    }
  }

  return result.join('\n');
};

// Comprimir cada archivo
const compressedFiles = {};
let originalTotal = 0;
let compressedTotal = 0;

for (const [filename, content] of Object.entries(payload.implementation.files)) {
  const original = content.length;
  const compressed = extractSignatures(content, filename);
  originalTotal += original;
  compressedTotal += compressed.length;
  compressedFiles[filename] = compressed;
}

const compressedPayload = {
  ...payload,
  implementation: {
    files: compressedFiles
  }
};

const reduction = Math.round((1 - compressedTotal / originalTotal) * 100);

return {
  payload: JSON.stringify(compressedPayload),
  stats: {
    original_chars: originalTotal,
    compressed_chars: compressedTotal,
    reduction_percent: reduction
  }
};

